std::expected<void, NetError> WebSocketClient::connect(
    const std::string& url,
    const std::unordered_map<std::string, std::string>& headers
) {
    if (m_connected.load()) {
        return std::unexpected(NetError::ConnectionFailed);
    }
    
    // Parse URL
    std::string host, path;
    int port = 80;
    bool useSSL = false;
    
    if (url.find("wss://") == 0) {
        useSSL = true;
        port = 443;
        size_t start = 6;
        size_t end = url.find("/", start);
        if (end == std::string::npos) {
            host = url.substr(start);
            path = "/";
        } else {
            host = url.substr(start, end - start);
            path = url.substr(end);
        }
    } else if (url.find("ws://") == 0) {
        size_t start = 5;
        size_t end = url.find("/", start);
        if (end == std::string::npos) {
            host = url.substr(start);
            path = "/";
        } else {
            host = url.substr(start, end - start);
            path = url.substr(end);
        }
    } else {
        return std::unexpected(NetError::InvalidResponse);
    }
    
    // Check for port in host
    size_t colonPos = host.find(":");
    if (colonPos != std::string::npos) {
        port = std::stoi(host.substr(colonPos + 1));
        host = host.substr(0, colonPos);
    }
    
    // Create socket
    EnsureWSA();
    SOCKET sock = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP);
    if (sock == INVALID_SOCKET) {
        return std::unexpected(NetError::ConnectionFailed);
    }
    
    SocketHandle socket(sock);
    
    // Connect
    struct addrinfo hints = {0};
    hints.ai_family = AF_INET;
    hints.ai_socktype = SOCK_STREAM;
    hints.ai_protocol = IPPROTO_TCP;
    
    struct addrinfo* result = nullptr;
    std::string portStr = std::to_string(port);
    
    if (getaddrinfo(host.c_str(), portStr.c_str(), &hints, &result) != 0) {
        return std::unexpected(NetError::ConnectionFailed);
    }
    
    if (connect(sock, result->ai_addr, (int)result->ai_addrlen) == SOCKET_ERROR) {
        freeaddrinfo(result);
        return std::unexpected(NetError::ConnectionFailed);
    }
    
    freeaddrinfo(result);
    
    // Perform WebSocket handshake
    auto handshakeResult = performHandshake(url, headers);
    if (!handshakeResult) {
        return handshakeResult;
    }
    
    m_socket = socket.release();
    m_connected = true;
    m_running = true;
    
    // Start receive thread
    m_receiveThread = std::thread(&WebSocketClient::receiveLoop, this);
    
    return {};
}

std::expected<void, NetError> WebSocketClient::performHandshake(
    const std::string& url,
    const std::unordered_map<std::string, std::string>& headers
) {
    // Build handshake request
    std::ostringstream request;
    request << "GET " << url << " HTTP/1.1\r\n";
    request << "Host: " << url << "\r\n";
    request << "Upgrade: websocket\r\n";
    request << "Connection: Upgrade\r\n";
    request << "Sec-WebSocket-Key: " << generateWebSocketKey() << "\r\n";
    request << "Sec-WebSocket-Version: 13\r\n";
    
    // Add custom headers
    for (const auto& [key, value] : headers) {
        request << key << ": " << value << "\r\n";
    }
    
    request << "\r\n";
    
    // Send handshake
    std::string handshake = request.str();
    if (send((SOCKET)m_socket, handshake.c_str(), handshake.length(), 0) == SOCKET_ERROR) {
        return std::unexpected(NetError::ConnectionFailed);
    }
    
    // Read response
    std::vector<char> buffer(1024);
    int received = recv((SOCKET)m_socket, buffer.data(), buffer.size(), 0);
    if (received <= 0) {
        return std::unexpected(NetError::ConnectionFailed);
    }
    
    // Parse response
    std::string response(buffer.data(), received);
    if (response.find("101 Switching Protocols") == std::string::npos) {
        return std::unexpected(NetError::ConnectionFailed);
    }
    
    return {};
}

std::string WebSocketClient::generateWebSocketKey() {
    // Generate random 16-byte key and base64 encode
    std::random_device rd;
    std::mt19937 gen(rd());
    std::uniform_int_distribution<> dis(0, 255);
    
    std::vector<uint8_t> key(16);
    for (auto& byte : key) {
        byte = dis(gen);
    }
    
    // Base64 encode
    static const char* base64_chars = 
        "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
    
    std::string encoded;
    int val = 0;
    int valb = -6;
    
    for (uint8_t c : key) {
        val = (val << 8) + c;
        valb += 8;
        while (valb >= 0) {
            encoded.push_back(base64_chars[(val >> valb) & 0x3F]);
            valb -= 6;
        }
    }
    
    if (valb > -6) {
        encoded.push_back(base64_chars[((val << 8) >> (valb + 8)) & 0x3F]);
    }
    
    while (encoded.size() % 4) {
        encoded.push_back('=');
    }
    
    return encoded;
}

std::expected<void, NetError> WebSocketClient::sendText(const std::string& message) {
    return sendFrame(WebSocketFrame::Opcode::Text, 
                    std::vector<uint8_t>(message.begin(), message.end()));
}

std::expected<void, NetError> WebSocketClient::sendFrame(
    WebSocketFrame::Opcode opcode,
    const std::vector<uint8_t>& payload,
    bool isFinal
) {
    if (!m_connected.load()) {
        return std::unexpected(NetError::ConnectionFailed);
    }
    
    // Construct frame
    std::vector<uint8_t> frame;
    frame.reserve(10 + payload.size());
    
    // First byte: FIN + opcode
    uint8_t firstByte = 0;
    if (isFinal) firstByte |= 0x80;
    firstByte |= static_cast<uint8_t>(opcode);
    frame.push_back(firstByte);
    
    // Payload length
    if (payload.size() < 126) {
        frame.push_back(static_cast<uint8_t>(payload.size()));
    } else if (payload.size() < 65536) {
        frame.push_back(126);
        frame.push_back((payload.size() >> 8) & 0xFF);
        frame.push_back(payload.size() & 0xFF);
    } else {
        frame.push_back(127);
        for (int i = 7; i >= 0; --i) {
            frame.push_back((payload.size() >> (i * 8)) & 0xFF);
        }
    }
    
    // Payload
    frame.insert(frame.end(), payload.begin(), payload.end());
    
    // Send
    if (send((SOCKET)m_socket, (const char*)frame.data(), frame.size(), 0) == SOCKET_ERROR) {
        return std::unexpected(NetError::WriteFailed);
    }
    
    return {};
}

std::expected<WebSocketFrame, NetError> WebSocketClient::receiveFrame(
    std::chrono::milliseconds timeout
) {
    if (!m_connected.load()) {
        return std::unexpected(NetError::ConnectionFailed);
    }
    
    // Set socket timeout
    DWORD timeoutMs = static_cast<DWORD>(timeout.count());
    setsockopt((SOCKET)m_socket, SOL_SOCKET, SO_RCVTIMEO, 
               (const char*)&timeoutMs, sizeof(timeoutMs));
    
    // Read first 2 bytes
    uint8_t header[2];
    int received = recv((SOCKET)m_socket, (char*)header, 2, 0);
    if (received != 2) {
        return std::unexpected(NetError::ReadFailed);
    }
    
    WebSocketFrame frame;
    frame.isFinal = (header[0] & 0x80) != 0;
    frame.opcode = static_cast<WebSocketFrame::Opcode>(header[0] & 0x0F);
    
    // Parse payload length
    uint64_t payloadLength = header[1] & 0x7F;
    if (payloadLength == 126) {
        uint16_t len;
        recv((SOCKET)m_socket, (char*)&len, 2, 0);
        payloadLength = ntohs(len);
    } else if (payloadLength == 127) {
        uint64_t len;
        recv((SOCKET)m_socket, (char*)&len, 8, 0);
        payloadLength = be64toh(len);
    }
    
    // Read payload
    frame.payload.resize(payloadLength);
    size_t totalReceived = 0;
    while (totalReceived < payloadLength) {
        received = recv((SOCKET)m_socket, 
                       (char*)frame.payload.data() + totalReceived,
                       payloadLength - totalReceived, 0);
        if (received <= 0) {
            return std::unexpected(NetError::ReadFailed);
        }
        totalReceived += received;
    }
    
    return frame;
}

void WebSocketClient::receiveLoop() {
    while (m_running.load()) {
        auto frameResult = receiveFrame(std::chrono::milliseconds(100));
        if (frameResult) {
            std::lock_guard lock(m_handlerMutex);
            if (m_messageHandler) {
                m_messageHandler(frameResult.value());
            }
        }
    }
}

