    if (!socket_handle || !data) return 0;
    
    SOCKET sock = (SOCKET)socket_handle;
    int sent = send(sock, data, static_cast<int>(data_size), 0);
    return (sent == SOCKET_ERROR) ? 0 : sent;
}

