    if (!socket_handle || !buffer) return 0;
    
    SOCKET sock = (SOCKET)socket_handle;
    int received = recv(sock, buffer, static_cast<int>(buffer_size), 0);
    return (received == SOCKET_ERROR) ? 0 : received;
}

