std::expected<HttpResponse, NetError> HttpClient::executeWithRetry(
    const std::string& method,
    const std::string& url,
    const std::string& body,
    const std::unordered_map<std::string, std::string>& headers,
    int retryCount
) {
    if (retryCount > m_config.maxRetries) {
        return std::unexpected(NetError::Timeout);
    }
    
    auto result = executeRequest(method, url, body, headers);
    
    if (!result) {
        m_errorCount.fetch_add(1);
        
        if (result.error() == NetError::Timeout || 
            result.error() == NetError::ConnectionFailed) {
            // Retry with exponential backoff
            std::this_thread::sleep_for(
                std::chrono::milliseconds(100 * (1 << retryCount))
            );
            return executeWithRetry(method, url, body, headers, retryCount + 1);
        }
        
        return result;
    }
    
    m_requestCount.fetch_add(1);
    m_bytesTransferred.fetch_add(result->bytesRead);
    
    return result;
}

