    if (m_config.apiKey) {
        netConfig.apiKey = *m_config.apiKey;
    }
    
    auto& netManager = Net::NetworkManager::instance();
    auto netResult = netManager.initialize(netConfig);
    if (!netResult) {
        log("Failed to initialize network stack", spdlog::level::critical);
        return std::unexpected(IDEError::InitializationFailed);
    }
    
    log("Network stack initialized", spdlog::level::debug);
    
    // Initialize components
    auto componentResult = initializeComponents();
    if (!componentResult) {
        log("Component initialization failed", spdlog::level::critical);
        return componentResult;
    }
    
    log("Components initialized", spdlog::level::debug);
    
    // Wire components together
    auto wiringResult = wireComponents();
    if (!wiringResult) {
        log("Component wiring failed", spdlog::level::critical);
        return wiringResult;
    }
    
    log("Components wired", spdlog::level::debug);
    
    // Start background services
    auto serviceResult = startBackgroundServices();
    if (!serviceResult) {
        log("Background services failed to start", spdlog::level::critical);
        return serviceResult;
    }
    
    log("Background services started", spdlog::level::debug);
    
    // Initialize swarm orchestrator if enabled
    if (m_config.enableSwarm) {
        m_swarmOrchestrator = std::make_unique<SwarmOrchestrator>(m_config.maxAgents);
        log("Swarm orchestrator initialized", spdlog::level::debug);
    }
    
    // Initialize chain-of-thought if enabled
    if (m_config.enableChainOfThought) {
        m_chainOfThought = std::make_unique<ChainOfThought>();
        log("Chain-of-thought initialized", spdlog::level::debug);
    }
    
    log("Agentic IDE initialized successfully", spdlog::level::info);
    return {};
}

Result<void> AgenticIDE::start() {
    if (m_running.exchange(true)) {
        log("IDE already running", spdlog::level::warn);
        return std::unexpected(IDEError::AlreadyRunning);
    }
    
    log("Starting Agentic IDE...", spdlog::level::info);
    
    // Start background services
    auto serviceResult = startBackgroundServices();
    if (!serviceResult) {
        m_running = false;
        return serviceResult;
    }
    
    // Start swarm orchestrator if enabled
    if (m_swarmOrchestrator) {
        m_swarmOrchestrator->startAutonomousMode();
        log("Swarm orchestrator started", spdlog::level::debug);
    }
    
    log("Agentic IDE started successfully", spdlog::level::info);
    return {};
}

void AgenticIDE::stop() {
    if (!m_running.exchange(false)) {
        log("IDE not running", spdlog::level::warn);
        return;
    }
    
    log("Stopping Agentic IDE...", spdlog::level::info);
    
    // Stop background services
    stopBackgroundServices();
    
    // Stop swarm orchestrator if enabled
    if (m_swarmOrchestrator) {
        m_swarmOrchestrator->stopAutonomousMode();
        log("Swarm orchestrator stopped", spdlog::level::debug);
    }
    
    // Notify components to stop
    if (m_orchestrator) {
        m_orchestrator->stopAutonomousMode();
    }
    
    if (m_zeroDayAgent) {
        m_zeroDayAgent->shutdown();
    }
    
    // Shutdown network stack
    Net::NetworkManager::instance().shutdown();
    
    log("Agentic IDE stopped", spdlog::level::info);
}

void AgenticIDE::processConsoleInput() {
    log("Console input processor started", spdlog::level::debug);
    
    // Create enhanced CLI
    EnhancedCLI cli;
    
    // Register IDE commands
    cli.registerCommand({
        "status",
        "Show IDE status",
        {"st"},
        [this](const std::vector<std::string>& args) {
            auto status = getStatus();
            return std::expected<std::string, CLIError>(status.dump(2));
        },
        "status",
        "Display current IDE status"
    });
    
    cli.registerCommand({
        "generate",
        "Generate using inference engine",
        {"gen", "g"},
        [this](const std::vector<std::string>& args) {
            if (args.empty()) {
                return std::expected<std::string, CLIError>(
                    std::unexpected(CLIError::InvalidArguments)
                );
            }
            
            auto result = m_inferenceEngine->generate(
                args[0], 0.7f, 0.9f, args.size() > 1 ? std::stoi(args[1]) : 512
            );
            
            if (!result) {
                return std::expected<std::string, CLIError>(
                    std::unexpected(CLIError::ExecutionFailed)
                );
            }
            
            return result->text;
        },
        "generate <prompt> [max_tokens]",
        "Generate text using the inference engine"
    });
    
    cli.registerCommand({
        "swarm",
        "Execute with swarm intelligence",
        {"sw", "multi"},
        [this](const std::vector<std::string>& args) {
            if (!m_swarmOrchestrator) {
                return std::expected<std::string, CLIError>(
                    std::unexpected(CLIError::ExecutionFailed)
                );
            }
            
            if (args.empty()) {
                return std::expected<std::string, CLIError>(
                    std::unexpected(CLIError::InvalidArguments)
                );
            }
            
            std::string task = std::accumulate(args.begin(), args.end(), std::string(),
                [](const std::string& a, const std::string& b) {
                    return a.empty() ? b : a + " " + b;
                });
            
            auto result = m_swarmOrchestrator->executeTask(task);
            if (!result) {
                return std::expected<std::string, CLIError>(
                    std::unexpected(CLIError::ExecutionFailed)
                );
            }
            
            return result.value();
        },
        "swarm <task>",
        "Execute task using swarm intelligence"
    });
    
    cli.registerCommand({
        "chain",
        "Execute with chain-of-thought",
        {"cot", "reason"},
        [this](const std::vector<std::string>& args) {
            if (!m_chainOfThought) {
                return std::expected<std::string, CLIError>(
                    std::unexpected(CLIError::ExecutionFailed)
                );
            }
            
            if (args.empty()) {
                return std::expected<std::string, CLIError>(
                    std::unexpected(CLIError::InvalidArguments)
                );
            }
            
            std::string goal = std::accumulate(args.begin(), args.end(), std::string(),
                [](const std::string& a, const std::string& b) {
                    return a.empty() ? b : a + " " + b;
                });
            
            auto context = std::unordered_map<std::string, std::string>{
                {"mode", "cli"},
                {"timestamp", std::to_string(
                    std::chrono::system_clock::to_time_t(std::chrono::system_clock::now())
                )}
            };
            
            auto result = m_chainOfThought->generateChain(goal, context);
            if (!result) {
                return std::expected<std::string, CLIError>(
                    std::unexpected(CLIError::ExecutionFailed)
                );
            }
            
            auto explanation = m_chainOfThought->generateExplanation(result.value());
            if (!explanation) {
                return std::expected<std::string, CLIError>(
                    std::unexpected(CLIError::ExecutionFailed)
                );
            }
            
            return explanation.value();
        },
        "chain <goal>",
        "Execute with step-by-step reasoning"
    });
    
    cli.registerCommand({
        "download-model",
        "Download model from URL",
        {"dl", "download"},
        [this](const std::vector<std::string>& args) {
            if (args.empty()) {
                return std::expected<std::string, CLIError>(
                    std::unexpected(CLIError::InvalidArguments)
                );
            }
            
            std::string url = args[0];
            std::string outputPath = args.size() > 1 ? args[1] : "./models/";
            
            // Real download using network stack
            auto& netManager = Net::NetworkManager::instance();
            auto& client = netManager.getHttpClient();
            
            auto result = client.get(url);
            if (!result) {
                return std::expected<std::string, CLIError>(
                    std::unexpected(CLIError::ExecutionFailed)
                );
            }
            
            // Save to file
            std::string filename = url.substr(url.find_last_of("/") + 1);
            std::string fullPath = outputPath + filename;
            
            std::ofstream file(fullPath, std::ios::binary);
            if (!file) {
                return std::expected<std::string, CLIError>(
                    std::unexpected(CLIError::ExecutionFailed)
                );
            }
            
            file << result->body;
            file.close();
            
            return std::string("Downloaded: ") + fullPath;
        },
        "download-model <url> [output_path]",
        "Download model from URL"
    });
    
    // Run CLI
    auto cliResult = cli.runInteractive();
    if (!cliResult) {
        log("CLI error", spdlog::level::error);
    }
    
    log("Console input processor stopped", spdlog::level::debug);
}

